#include<iostream>#include<vector>#include<algorithm>using namespace std;int main(){    int t;    cin>>t;        while(t--){        vector<int> v;        int n,k;        cin>>n>>k;                int a;        for(int i=0 ; i<n ; i++){            cin>>a;            v.push_back(a);        }                sort(v.begin(),v.end());                int count=1;        int maxcount = 1;        vector<int> res;         for(int i=0 ; i<n-1 ; i++){            if(abs(v[i] - v[i+1]) <= k){                count++;            if(count>maxcount){                maxcount = count;            }            }            else{                count=1;            }        }        cout<<n-maxcount<<endl;    }    return 0;}